final:
module RefModule(
    input clk,
    input rst,
    input en,
    input load,
    input [15:0] load_value,
    output reg [15:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
  if (rst)
    count <= 0;
  else if (load)
    count <= load_value;
  else if (en)
    count <= count + 1;
end

endmodule
